import React, { useState } from 'react'
import { render, screen, fireEvent, waitFor, act } from '@testing-library/react'
import '@testing-library/jest-dom'
import { autoUpdate } from '@floating-ui/dom'
import { TooltipController } from '../components/TooltipController'
import {
  advanceTimers,
  flushMicrotasks,
  flushPendingTimers,
  hoverAnchor,
  unhoverAnchor,
  waitForTooltip,
  waitForTooltipToStopShowing,
} from './test-utils'

jest.mock('@floating-ui/dom', () => {
  const originalModule = jest.requireActual('@floating-ui/dom')
  return {
    ...originalModule,
    autoUpdate: jest.fn().mockImplementation((reference, floating, update) => {
      if (update) update()
      return jest.fn()
    }),
  }
})

describe('tooltip interaction behavior', () => {
  beforeEach(() => {
    jest.useFakeTimers()
    jest.clearAllMocks()
  })

  afterEach(() => {
    flushPendingTimers()
    jest.useRealTimers()
  })

  const renderAndFlush = async (ui) => {
    let view
    await act(async () => {
      view = render(ui)
      await Promise.resolve()
    })
    return view
  }

  test('opens on click when click is the configured trigger', async () => {
    await renderAndFlush(
      <>
        <span data-tooltip-id="click-only-test">Hover Me</span>
        <TooltipController
          id="click-only-test"
          content="Click Only Test"
          openEvents={{ click: true }}
          closeEvents={{ click: true }}
        />
      </>,
    )

    const anchor = screen.getByText('Hover Me')

    hoverAnchor(anchor, 100)
    expect(document.getElementById('click-only-test')).not.toBeInTheDocument()

    fireEvent.click(anchor)
    await flushMicrotasks()
    const tooltip = await waitForTooltip('click-only-test')
    expect(tooltip).toHaveTextContent('Click Only Test')
  })

  test('opens on click when the anchor stops propagation', async () => {
    await renderAndFlush(
      <>
        <button
          type="button"
          data-tooltip-id="stopped-click-test"
          onClick={(event) => event.stopPropagation()}
        >
          Click Me
        </button>
        <TooltipController id="stopped-click-test" content="Stopped Click Test" openOnClick />
      </>,
    )

    fireEvent.click(screen.getByText('Click Me'))
    await flushMicrotasks()

    const tooltip = await waitForTooltip('stopped-click-test')
    expect(tooltip).toHaveTextContent('Stopped Click Test')
  })

  test('stops showing after scroll and resize global close events', async () => {
    await renderAndFlush(
      <>
        <span data-tooltip-id="global-events-test">Hover Me</span>
        <TooltipController
          id="global-events-test"
          content="Global Events Test"
          globalCloseEvents={{ scroll: true, resize: true }}
        />
      </>,
    )

    const anchor = screen.getByText('Hover Me')

    hoverAnchor(anchor, 1000)
    await waitForTooltip('global-events-test')

    fireEvent.scroll(window)
    advanceTimers(100)
    await flushMicrotasks()
    await waitForTooltipToStopShowing('global-events-test')

    // Allow the tooltip to fully unmount before re-hovering
    advanceTimers(100)
    await flushMicrotasks()

    hoverAnchor(anchor, 1000)
    await flushMicrotasks()
    await waitForTooltip('global-events-test')

    fireEvent.resize(window)
    advanceTimers(100)
    await flushMicrotasks()
    await waitForTooltipToStopShowing('global-events-test')
  })

  test('keeps a clickable tooltip open while the pointer moves into it', async () => {
    await renderAndFlush(
      <>
        <span data-tooltip-id="clickable-test">Hover Me</span>
        <TooltipController
          id="clickable-test"
          content="Clickable Test"
          clickable
          globalCloseEvents={{ scroll: true, resize: true }}
        />
      </>,
    )

    const anchor = screen.getByText('Hover Me')

    hoverAnchor(anchor, 1000)
    const tooltip = await waitForTooltip('clickable-test')

    unhoverAnchor(anchor, 0)
    fireEvent.mouseEnter(tooltip)
    advanceTimers(150) // past clickable's 100ms hide-delay so the close timer fires
    await flushMicrotasks()

    const elem = screen.getByRole('tooltip')
    expect(elem).toBeInTheDocument()
    expect(elem).toHaveClass('react-tooltip__show')

    fireEvent.mouseLeave(tooltip)
    await flushMicrotasks()
    await waitForTooltipToStopShowing('clickable-test')
  })

  test('keeps autoUpdate wired when an active anchor is removed', async () => {
    const RemovableTest = () => {
      const [showAnchor, setShowAnchor] = useState(true)

      return (
        <div>
          {showAnchor && <span data-tooltip-id="removable-test">Hover Me</span>}
          <button onClick={() => setShowAnchor(false)}>Remove Anchor</button>
          <TooltipController id="removable-test" content="Removable Test" />
        </div>
      )
    }

    await renderAndFlush(<RemovableTest />)

    const anchor = screen.getByText('Hover Me')
    hoverAnchor(anchor, 500)
    await waitForTooltip('removable-test')

    fireEvent.click(screen.getByText('Remove Anchor'))
    await flushMicrotasks()
    anchor.setAttribute('data-tooltip-id', 'different-id')
    mutationObserverController.triggerAll([
      {
        type: 'attributes',
        attributeName: 'data-tooltip-id',
        target: anchor,
        oldValue: 'attribute-removal-test',
      },
    ])

    unhoverAnchor(anchor, 100)
    await waitForTooltipToStopShowing('attribute-removal-test')
  })

  test('does not reopen or close when delegated hover events stay inside the same anchor', async () => {
    render(
      <>
        <button data-tooltip-id="delegated-hover-test" type="button">
          Hover Me
          <span>Inner target</span>
        </button>
        <TooltipController id="delegated-hover-test" content="Delegated Hover Test" />
      </>,
    )

    const anchor = screen.getByRole('button', { name: /hover me inner target/i })
    const innerTarget = screen.getByText('Inner target')

    hoverAnchor(anchor, 100)
    await waitForTooltip('delegated-hover-test')

    fireEvent.mouseOver(innerTarget, { relatedTarget: anchor })
    fireEvent.mouseOut(anchor, { relatedTarget: innerTarget })

    expect(document.getElementById('delegated-hover-test')).toBeInTheDocument()
  })

  test('does not close on focus transitions inside the same anchor', async () => {
    render(
      <>
        <div data-tooltip-id="focus-anchor-test" tabIndex={0}>
          Focus Anchor
          <button type="button">Inner Button</button>
        </div>
        <TooltipController id="focus-anchor-test" content="Focus Anchor Test" />
      </>,
    )

    const anchor = screen.getByText('Focus Anchor').closest('div')
    const innerButton = screen.getByRole('button', { name: 'Inner Button' })

    fireEvent.focus(anchor)
    await waitForTooltip('focus-anchor-test')

    fireEvent.focusOut(anchor, { relatedTarget: innerButton })

    expect(document.getElementById('focus-anchor-test')).toBeInTheDocument()
  })
})

type AnchorRegistrySubscriber = (anchors: HTMLElement[], error: Error | null) => void

type AnchorRegistryEntry = {
  anchors: HTMLElement[]
  error: Error | null
  subscribers: Set<AnchorRegistrySubscriber>
  /**
   * When the selector is a simple `[data-tooltip-id='value']` pattern,
   * this holds the extracted tooltip ID so we can skip expensive
   * querySelectorAll calls when the mutation doesn't affect it.
   */
  tooltipId: string | null
}

const registry = new Map<string, AnchorRegistryEntry>()

let documentObserver: MutationObserver | null = null

/**
 * Extract a tooltip ID from a simple `[data-tooltip-id='value']` selector.
 * Returns null for complex or custom selectors.
 */
function extractTooltipId(selector: string): string | null {
  const match = selector.match(/^\[data-tooltip-id=(['"])((?:\\.|(?!\1).)*)\1\]$/)
  return match ? match[2].replace(/\\(['"])/g, '$1') : null
}

function areAnchorListsEqual(left: HTMLElement[], right: HTMLElement[]) {
  if (left.length !== right.length) {
    return false
  }

  return left.every((anchor, index) => anchor === right[index])
}

function readAnchorsForSelector(selector: string) {
  try {
    return {
      anchors: Array.from(document.querySelectorAll<HTMLElement>(selector)),
      error: null,
    }
  } catch (error) {
    return {
      anchors: [],
      error: error instanceof Error ? error : new Error(String(error)),
    }
  }
}

function notifySubscribers(entry: AnchorRegistryEntry) {
  entry.subscribers.forEach((subscriber) => subscriber(entry.anchors, entry.error))
}

function refreshEntry(selector: string, entry: AnchorRegistryEntry) {
  const nextState = readAnchorsForSelector(selector)
  const nextErrorMessage = nextState.error?.message ?? null
  const previousErrorMessage = entry.error?.message ?? null

  if (
    areAnchorListsEqual(entry.anchors, nextState.anchors) &&
    nextErrorMessage === previousErrorMessage
  ) {
    return
  }

  const nextEntry = {
    ...entry,
    anchors: nextState.anchors,
    error: nextState.error,
  }

  registry.set(selector, nextEntry)
  notifySubscribers(nextEntry)
}

function refreshAllEntries() {
  registry.forEach((entry, selector) => {
    refreshEntry(selector, entry)
  })
}

let refreshScheduled = false
let pendingTooltipIds: Set<string> | null = null
let pendingFullRefresh = false

function scheduleRefresh(affectedTooltipIds: Set<string> | null) {
  if (affectedTooltipIds) {
    if (!pendingTooltipIds) {
      pendingTooltipIds = new Set()
    }
    affectedTooltipIds.forEach((id) => pendingTooltipIds!.add(id))
  } else {
    pendingFullRefresh = true
  }

  if (refreshScheduled) {
    return
  }
  refreshScheduled = true

  const flush = () => {
    refreshScheduled = false
    const fullRefresh = pendingFullRefresh
    const ids = pendingTooltipIds
    pendingFullRefresh = false
    pendingTooltipIds = null

    if (fullRefresh) {
      refreshAllEntries()
    } else if (ids && ids.size > 0) {
      refreshEntriesForTooltipIds(ids)
    }
  }

  if (typeof requestAnimationFrame === 'function') {
    requestAnimationFrame(flush)
  } else {
    Promise.resolve().then(flush)
  }
}

/**
 * Only refresh entries whose tooltipId is in the affected set,
 * plus any entries with custom (non-tooltipId) selectors.
 */
function refreshEntriesForTooltipIds(affectedIds: Set<string>) {
  registry.forEach((entry, selector) => {
    if (entry.tooltipId === null || affectedIds.has(entry.tooltipId)) {
      refreshEntry(selector, entry)
    }
  })
}

/**
 * Collect tooltip IDs from mutation records. Returns null when targeted
 * analysis is not worthwhile (few registry entries, or too many nodes to scan).
 */
function collectAffectedTooltipIds(records: MutationRecord[]): Set<string> | null {
  // Targeted refresh only pays off when there are many distinct selectors.
  // With few entries, full refresh is already cheap — skip the analysis overhead.
  if (registry.size <= 4) {
    return null
  }

  const ids = new Set<string>()

  for (const record of records) {
    if (record.type === 'attributes') {
      const target = record.target as HTMLElement
      const currentId = target.getAttribute?.('data-tooltip-id')
      if (currentId) ids.add(currentId)
      if (record.oldValue) ids.add(record.oldValue)
      continue
    }

    if (record.type === 'childList') {
      const gatherIds = (nodes: NodeList) => {
        for (let i = 0; i < nodes.length; i++) {
          const node = nodes[i]
          if (node.nodeType !== Node.ELEMENT_NODE) continue
          const el = node as HTMLElement
          const id = el.getAttribute?.('data-tooltip-id')
          if (id) ids.add(id)
          // For large subtrees, bail out to full refresh to avoid double-scanning
          const descendants = el.querySelectorAll?.('[data-tooltip-id]')
          if (descendants) {
            if (descendants.length > 50) {
              return true // signal bail-out
            }
            for (let j = 0; j < descendants.length; j++) {
              const descId = descendants[j].getAttribute('data-tooltip-id')
              if (descId) ids.add(descId)
            }
          }
        }
        return false
      }
      if (gatherIds(record.addedNodes) || gatherIds(record.removedNodes)) {
        return null // large mutation — full refresh is cheaper
      }
      continue
    }
  }

  return ids
}

function ensureDocumentObserver() {
  if (documentObserver || typeof MutationObserver === 'undefined') {
    return
  }

  documentObserver = new MutationObserver((records) => {
    const affectedIds = collectAffectedTooltipIds(records)
    scheduleRefresh(affectedIds)
  })

  documentObserver.observe(document.body, {
    childList: true,
    subtree: true,
    attributes: true,
    attributeFilter: ['data-tooltip-id'],
    attributeOldValue: true,
  })
}

function cleanupDocumentObserverIfUnused() {
  if (registry.size !== 0 || !documentObserver) {
    return
  }

  documentObserver.disconnect()
  documentObserver = null
}

export function subscribeAnchorSelector(selector: string, subscriber: AnchorRegistrySubscriber) {
  let entry = registry.get(selector)

  if (!entry) {
    const initialState = readAnchorsForSelector(selector)
    entry = {
      anchors: initialState.anchors,
      error: initialState.error,
      subscribers: new Set(),
      tooltipId: extractTooltipId(selector),
    }
    registry.set(selector, entry)
  }

  entry.subscribers.add(subscriber)
  ensureDocumentObserver()
  subscriber([...entry.anchors], entry.error)

  return () => {
    const currentEntry = registry.get(selector)
    if (!currentEntry) {
      return
    }

    currentEntry.subscribers.delete(subscriber)
    if (currentEntry.subscribers.size === 0) {
      registry.delete(selector)
    }
    cleanupDocumentObserverIfUnused()
  }
}

/** @internal Reset module state between tests */
export function resetAnchorRegistry() {
  registry.clear()
  if (documentObserver) {
    documentObserver.disconnect()
    documentObserver = null
  }
  refreshScheduled = false
  pendingTooltipIds = null
  pendingFullRefresh = false
}
/**
 * Shared document event delegation.
 *
 * Instead of N tooltips each calling document.addEventListener(type, handler),
 * we maintain ONE document listener per event type. When the event fires,
 * we iterate through all registered handlers for that type.
 *
 * This reduces document-level listeners from O(N × eventTypes) to O(eventTypes).
 */

type Handler = (event: Event) => void

type DelegatedListener = {
  handlers: Set<Handler>
  dispatch: (event: Event) => void
  eventType: string
  capture: boolean
}

const handlersByType = new Map<string, DelegatedListener>()

function getListenerKey(eventType: string, capture: boolean): string {
  return `${eventType}:${capture ? 'capture' : 'bubble'}`
}

function getOrCreateListener(eventType: string, capture: boolean): DelegatedListener {
  const key = getListenerKey(eventType, capture)
  let listener = handlersByType.get(key)
  if (!listener) {
    const handlers = new Set<Handler>()
    const dispatch = (event: Event): void => {
      handlers.forEach((handler) => {
        handler(event)
      })
    }
    listener = { handlers, dispatch, eventType, capture }
    handlersByType.set(key, listener)
    document.addEventListener(eventType, dispatch, { capture })
  }
  return listener
}

/**
 * Register a handler for a document-level event type.
 * Returns an unsubscribe function.
 */
export function addDelegatedEventListener(
  eventType: string,
  handler: Handler,
  options: AddEventListenerOptions = {},
): () => void {
  const capture = Boolean(options.capture)
  const key = getListenerKey(eventType, capture)
  const listener = getOrCreateListener(eventType, capture)
  listener.handlers.add(handler)

  return () => {
    listener.handlers.delete(handler)
    if (listener.handlers.size === 0) {
      handlersByType.delete(key)
      document.removeEventListener(eventType, listener.dispatch, { capture })
    }
  }
}

/**
 * Reset for testing purposes.
 */
export function resetEventDelegation(): void {
  handlersByType.forEach((listener) => {
    document.removeEventListener(listener.eventType, listener.dispatch, {
      capture: listener.capture,
    })
  })
  handlersByType.clear()
}

import { useEffect, useMemo, useRef } from 'react'
import type { RefObject } from 'react'
import { autoUpdate } from '@floating-ui/dom'
import {
  debounce,
  getScrollParent,
  clearTimeoutRef,
  parseDataTooltipIdSelector,
  resolveDataTooltipAnchor,
} from '../../utils'
import type {
  AnchorCloseEvents,
  AnchorOpenEvents,
  GlobalCloseEvents,
  IPosition,
} from './TooltipTypes'
import { addDelegatedEventListener } from './event-delegation'

const useTooltipEvents = ({
  activeAnchor,
  anchorElements,
  anchorSelector,
  clickable,
  closeEvents,
  delayHide,
  delayShow,
  disableTooltip,
  float,
  globalCloseEvents,
  handleHideTooltipDelayed,
  handleShow,
  handleShowTooltipDelayed,
  handleTooltipPosition,
  hoveringTooltip,
  imperativeModeOnly,
  lastFloatPosition,
  openEvents,
  openOnClick,
  rendered,
  setActiveAnchor,
  show,
  tooltipHideDelayTimerRef,
  tooltipRef,
  tooltipShowDelayTimerRef,
  updateTooltipPosition,
}: {
  activeAnchor: HTMLElement | null
  anchorElements: HTMLElement[]
  anchorSelector: string
  clickable: boolean
  closeEvents?: AnchorCloseEvents
  delayHide: number
  delayShow: number
  disableTooltip?: (anchorRef: HTMLElement | null) => boolean
  float: boolean
  globalCloseEvents?: GlobalCloseEvents
  handleHideTooltipDelayed: (delay?: number) => void
  handleShow: (value: boolean) => void
  handleShowTooltipDelayed: (delay?: number) => void
  handleTooltipPosition: ({ x, y }: IPosition) => void
  hoveringTooltip: RefObject<boolean>
  imperativeModeOnly?: boolean
  lastFloatPosition: RefObject<IPosition | null>
  openEvents?: AnchorOpenEvents
  openOnClick: boolean
  rendered: boolean
  setActiveAnchor: (anchor: HTMLElement | null) => void
  show: boolean
  tooltipHideDelayTimerRef: RefObject<NodeJS.Timeout | null>
  tooltipRef: RefObject<HTMLElement | null>
  tooltipShowDelayTimerRef: RefObject<NodeJS.Timeout | null>
  updateTooltipPosition: () => void
}) => {
  // Ref-stable debounced handlers — avoids recreating debounce instances on every effect run
  // eslint-disable-next-line @typescript-eslint/no-unused-vars
  const debouncedShowRef = useRef(debounce((_anchor: HTMLElement | null) => {}, 50, true))
  const debouncedHideRef = useRef(debounce(() => {}, 50, true))

  // Cache scroll parents — only recompute when the element actually changes
  const anchorScrollParentRef = useRef<Element | null>(null)
  const tooltipScrollParentRef = useRef<Element | null>(null)
  const prevAnchorRef = useRef<HTMLElement | null>(null)
  const prevTooltipRef = useRef<HTMLElement | null>(null)

  if (activeAnchor !== prevAnchorRef.current) {
    prevAnchorRef.current = activeAnchor
    anchorScrollParentRef.current = getScrollParent(activeAnchor)
  }
  const currentTooltipEl = tooltipRef.current
  if (currentTooltipEl !== prevTooltipRef.current) {
    prevTooltipRef.current = currentTooltipEl
    tooltipScrollParentRef.current = getScrollParent(currentTooltipEl)
  }

  // Memoize event config objects — only rebuild when the relevant props change
  const hasClickEvent =
    openOnClick || openEvents?.click || openEvents?.dblclick || openEvents?.mousedown
  const actualOpenEvents: AnchorOpenEvents = useMemo(() => {
    const events: AnchorOpenEvents = openEvents
      ? { ...openEvents }
      : {
          mouseenter: true,
          focus: true,
          click: false,
          dblclick: false,
          mousedown: false,
        }
    if (!openEvents && openOnClick) {
      Object.assign(events, {
        mouseenter: false,
        focus: false,
        click: true,
      })
    }
    if (imperativeModeOnly) {
      Object.assign(events, {
        mouseenter: false,
        focus: false,
        click: false,
        dblclick: false,
        mousedown: false,
      })
    }
    return events
  }, [openEvents, openOnClick, imperativeModeOnly])

  const actualCloseEvents: AnchorCloseEvents = useMemo(() => {
    const events: AnchorCloseEvents = closeEvents
      ? { ...closeEvents }
      : {
          mouseleave: true,
          blur: true,
          click: false,
          dblclick: false,
          mouseup: false,
        }
    if (!closeEvents && openOnClick) {
      Object.assign(events, {
        mouseleave: false,
        blur: false,
      })
    }
    if (imperativeModeOnly) {
      Object.assign(events, {
        mouseleave: false,
        blur: false,
        click: false,
        dblclick: false,
        mouseup: false,
      })
    }
    return events
  }, [closeEvents, openOnClick, imperativeModeOnly])

  const actualGlobalCloseEvents: GlobalCloseEvents = useMemo(() => {
    const events: GlobalCloseEvents = globalCloseEvents
      ? { ...globalCloseEvents }
      : {
          escape: false,
          scroll: false,
          resize: false,
          clickOutsideAnchor: hasClickEvent || false,
        }
    if (imperativeModeOnly) {
      Object.assign(events, {
        escape: false,
        scroll: false,
        resize: false,
        clickOutsideAnchor: false,
      })
    }
    return events
  }, [globalCloseEvents, hasClickEvent, imperativeModeOnly])

  // --- Refs for values read inside event handlers (avoids effect deps) ---
  const activeAnchorRef = useRef(activeAnchor)
  activeAnchorRef.current = activeAnchor
  const showRef = useRef(show)
  showRef.current = show
  const anchorElementsRef = useRef(anchorElements)
  anchorElementsRef.current = anchorElements
  const handleShowRef = useRef(handleShow)
  handleShowRef.current = handleShow
  const handleTooltipPositionRef = useRef(handleTooltipPosition)
  handleTooltipPositionRef.current = handleTooltipPosition
  const updateTooltipPositionRef = useRef(updateTooltipPosition)
  updateTooltipPositionRef.current = updateTooltipPosition

  // --- Handler refs (updated every render, read via ref indirection in effects) ---
  const resolveAnchorElementRef = useRef<(target: EventTarget | null) => HTMLElement | null>(
    () => null,
  )
  const handleShowTooltipRef = useRef<(anchor: HTMLElement | null) => void>(() => {})
  const handleHideTooltipRef = useRef<() => void>(() => {})

  const dataTooltipId = anchorSelector ? parseDataTooltipIdSelector(anchorSelector) : null

  resolveAnchorElementRef.current = (target: EventTarget | null) => {
    const targetElement = target as HTMLElement | null

    if (!targetElement?.isConnected) {
      return null
    }

    if (dataTooltipId) {
      const matchedAnchor = resolveDataTooltipAnchor(targetElement, dataTooltipId)

      if (matchedAnchor && !disableTooltip?.(matchedAnchor)) {
        return matchedAnchor
      }
    } else if (anchorSelector) {
      try {
        const matchedAnchor =
          (targetElement.matches(anchorSelector)
            ? targetElement
            : targetElement.closest(anchorSelector)) ?? null

        if (matchedAnchor && !disableTooltip?.(matchedAnchor as HTMLElement)) {
          return matchedAnchor as HTMLElement
        }
      } catch {
        return null
      }
    }

    return (
      anchorElementsRef.current.find(
        (anchor) => anchor === targetElement || anchor.contains(targetElement),
      ) ?? null
    )
  }

  handleShowTooltipRef.current = (anchor: HTMLElement | null) => {
    if (!anchor) {
      return
    }
    if (!anchor.isConnected) {
      setActiveAnchor(null)
      return
    }
    if (disableTooltip?.(anchor)) {
      return
    }
    if (delayShow && activeAnchorRef.current && anchor !== activeAnchorRef.current) {
      // Moving to a different anchor while one is already active — defer the anchor
      // switch until the show delay fires to prevent content/position from updating
      // before visibility transitions complete.
      if (tooltipShowDelayTimerRef.current) {
        clearTimeout(tooltipShowDelayTimerRef.current)
      }
      tooltipShowDelayTimerRef.current = setTimeout(() => {
        setActiveAnchor(anchor)
        handleShow(true)
      }, delayShow)
    } else {
      setActiveAnchor(anchor)
      if (delayShow) {
        handleShowTooltipDelayed()
      } else {
        handleShow(true)
      }
    }

    if (tooltipHideDelayTimerRef.current) {
      clearTimeout(tooltipHideDelayTimerRef.current)
    }
  }

  handleHideTooltipRef.current = () => {
    if (clickable) {
      handleHideTooltipDelayed(delayHide || 100)
    } else if (delayHide) {
      handleHideTooltipDelayed()
    } else {
      handleShow(false)
    }

    if (tooltipShowDelayTimerRef.current) {
      clearTimeout(tooltipShowDelayTimerRef.current)
    }
  }

  // Update debounced callbacks to always delegate to latest handler refs
  const debouncedShow = debouncedShowRef.current
  const debouncedHide = debouncedHideRef.current
  debouncedShow.setCallback((anchor: HTMLElement | null) => handleShowTooltipRef.current(anchor))
  debouncedHide.setCallback(() => handleHideTooltipRef.current())

  // --- Effect 1: Delegated anchor events + tooltip hover ---
  // Only re-runs when the set of active event types or interaction mode changes.
  // Handlers read reactive values (activeAnchor, show, etc.) from refs at invocation
  // time, so this effect is decoupled from show/hide state changes.
  useEffect(() => {
    const cleanupFns: (() => void)[] = []

    const addDelegatedListener = (
      eventType: string,
      listener: (event: Event) => void,
      options?: AddEventListenerOptions,
    ) => {
      cleanupFns.push(addDelegatedEventListener(eventType, listener, options))
